logger = logging.getLogger()
logger.setLevel(os.getenv("LOG_LEVEL", "INFO").upper())

s3 = boto3.client("s3")
sns = boto3.client("sns")

SNS_TOPIC_ARN = os.getenv("SNS_TOPIC_ARN", "")
OUTPUT_BUCKET = os.getenv("OUTPUT_BUCKET", "")
OUTPUT_PREFIX = os.getenv("OUTPUT_PREFIX", "processed/")
WRITE_JSON_RESULTS = os.getenv("WRITE_JSON_RESULTS", "true").lower() in ("1", "true", "yes", "y")
MAX_BYTES_TO_READ = int(os.getenv("MAX_BYTES_TO_READ", str(25 * 1024 * 1024)))  # 25MB default


def _now_ms() -> int:
    return int(time.time() * 1000)


def _safe_json(obj):
    try:
        return json.dumps(obj, default=str, ensure_ascii=False)
    except Exception:
        return json.dumps({"error": "failed_to_serialize"})


def _publish_sns(subject: str, message: dict):
    if not SNS_TOPIC_ARN:
        logger.info("SNS_TOPIC_ARN not set; skipping SNS publish. subject=%s message=%s", subject, _safe_json(message))
        return
    sns.publish(
        TopicArn=SNS_TOPIC_ARN,
        Subject=subject[:100],
        Message=_safe_json(message),
    )


def _parse_s3_event(event):
    records = event.get("Records") or []
    out = []
    for r in records:
        s3info = (r.get("s3") or {})
        bucket = ((s3info.get("bucket") or {}).get("name")) or ""
        key = ((s3info.get("object") or {}).get("key")) or ""
        if key:
            key = unquote_plus(key)
        if bucket and key:
            out.append((bucket, key, r))
    return out


def _head_object(bucket, key):
    return s3.head_object(Bucket=bucket, Key=key)


def _get_object_bytes(bucket, key, max_bytes=MAX_BYTES_TO_READ):
    obj = s3.get_object(Bucket=bucket, Key=key)
    body = obj["Body"]
    data = body.read(max_bytes + 1)
    if len(data) > max_bytes:
        raise ValueError(f"Object too large to read in Lambda (>{max_bytes} bytes).")
    return data, obj


def _put_object(bucket, key, data: bytes, content_type="application/octet-stream", metadata=None):
    kwargs = {
        "Bucket": bucket,
        "Key": key,
        "Body": data,
        "ContentType": content_type,
    }
    if metadata:
        kwargs["Metadata"] = {str(k): str(v) for k, v in metadata.items()}
    s3.put_object(**kwargs)


def _choose_output_bucket(input_bucket):
    return OUTPUT_BUCKET or input_bucket


def _build_output_key(input_key, suffix):
    base = input_key.rsplit("/", 1)[-1]
    return f"{OUTPUT_PREFIX.rstrip('/')}/{base}{suffix}"


def _basic_image_analysis(data: bytes, content_type: str):
    # MVP placeholder: compute basic metadata without external deps.
    # Extend later with Pillow/OpenCV/Rekognition, etc.
    return {
        "byte_size": len(data),
        "content_type": content_type or "application/octet-stream",
        "sha256": __import__("hashlib").sha256(data).hexdigest(),
        "magic": data[:16].hex(),
    }


def _infer_content_type(head, key):
    ct = head.get("ContentType") or ""
    if ct:
        return ct
    k = key.lower()
    if k.endswith(".jpg") or k.endswith(".jpeg"):
        return "image/jpeg"
    if k.endswith(".png"):
        return "image/png"
    if k.endswith(".gif"):
        return "image/gif"
    if k.endswith(".webp"):
        return "image/webp"
    if k.endswith(".bmp"):
        return "image/bmp"
    if k.endswith(".tif") or k.endswith(".tiff"):
        return "image/tiff"
    return "application/octet-stream"


def handler(event, context):
    request_id = getattr(context, "aws_request_id", str(uuid.uuid4()))
    start_ms = _now_ms()

    logger.info("request_id=%s event=%s", request_id, _safe_json(event))

    items = _parse_s3_event(event)
    if not items:
        msg = {
            "request_id": request_id,
            "status": "no_records",
            "detail": "No S3 records found in event.",
        }
        logger.warning(_safe_json(msg))
        _publish_sns("ImageProcessor: No Records", msg)
        return msg

    results = []
    for (bucket, key, record) in items:
        item_start = _now_ms()
        try:
            head = _head_object(bucket, key)
            content_type = _infer_content_type(head, key)
            size = int(head.get("ContentLength") or 0)

            if size > MAX_BYTES_TO_READ:
                raise ValueError(f"Object size {size} exceeds MAX_BYTES_TO_READ={MAX_BYTES_TO_READ}")

            data, obj = _get_object_bytes(bucket, key, MAX_BYTES_TO_READ)

            analysis = _basic_image_analysis(data, content_type)

            output_bucket = _choose_output_bucket(bucket)
            output_key = _build_output_key(key, ".json")

            put_meta = {
                "source-bucket": bucket,
                "source-key": key,
                "request-id": request_id,
            }

            if WRITE_JSON_RESULTS:
                _put_object(
                    output_bucket,
                    output_key,
                    json.dumps(
                        {
                            "request_id": request_id,
                            "source": {"bucket": bucket, "key": key},
                            "s3": {
                                "etag": head.get("ETag", "").strip('"'),
                                "size": size,
                                "last_modified": str(head.get("LastModified", "")),
                                "content_type": content_type,
                            },
                            "analysis": analysis,
                            "timing_ms": {"item": _now_ms() - item_start},
                        },
                        ensure_ascii=False,
                        default=str,
                    ).encode("utf-8"),
                    content_type="application/json",
                    metadata=put_meta,
                )

            notification = {
                "request_id": request_id,
                "status": "processed",
                "source": {"bucket": bucket, "key": key},
                "output": {"bucket": output_bucket, "key": output_key if WRITE_JSON_RESULTS else None},
                "analysis": analysis,
                "timing_ms": {"item": _now_ms() - item_start},
            }
            _publish_sns("ImageProcessor: Processed", notification)

            results.append(notification)
            logger.info("request_id=%s processed=%s", request_id, _safe_json(notification))

        except Exception as e:
            err = {
                "request_id": request_id,
                "status": "error",
                "source": {"bucket": bucket, "key": key},
                "error": str(e),
                "traceback": traceback.format_exc(),
                "timing_ms": {"item": _now_ms() - item_start},
            }
            logger.error("request_id=%s error=%s", request_id, _safe_json(err))
            _publish_sns("ImageProcessor: Error", err)
            results.append(err)

    resp = {
        "request_id": request_id,
        "status": "ok",
        "count": len(results),
        "results": results,
        "timing_ms": {"total": _now_ms() - start_ms},
    }
    logger.info("request_id=%s response=%s", request_id, _safe_json(resp))
    return resp